const config      = $('InputData').first().json.config
const countersData = $('readCounters').all() || [];

const CC = config.COLUMNS.COUNTERS;

const counterName = "vypiska_ot_counter";
const format      = Object.values(config.REG_NUMBER_FORMATS)
  .find(f => f.counter_name === counterName);

if (!format) {
  throw new Error(`Формат для счётчика "${counterName}" не найден в конфиге`);
}

const counter = countersData.find(c =>
  c.json[CC.COUNTER_TYPE] === counterName
);

let current = counter
  ? (parseInt(counter.json[CC.CURRENT_VALUE]) || 0)
  : 0;

current += 1;

const now   = new Date();
const month = String(now.getMonth() + 1).padStart(2, "0");
const yy    = String(now.getFullYear()).slice(-2);

const regNumber = format.format
  .replace("{number}", current)
  .replace("{month}",  month)
  .replace("{yy}",     yy)
  .replace("{prefix}", format.prefix || "");

console.log(`🔢 Новый рег-номер выписки: ${regNumber} (счётчик: ${current})`);

return [
  {
    json: {
      regNumber,
      counterName,
      counterValue: current,
      variable: `<<${format.variable}>>`
    }
  }
];

