const OTV_ARRAY = ["Б1", "Б2", "Б3 3-5", "Б3 3-1", "Б3 3-4", "Б3 3-3", "Б3 3-2", "Б3 3-6", "Б3 1-6", "ОТВ А", "А1", "А2", "А3 1-6"];

// Значения для 9 ячеек по порядку столбцов
const values = [
  "0",                    // №
  fio, // Ф.И.О.
  job_post,            // Должность
  company,    // Место работы
  "удовлетворительно",    // Результат
  ud_reg_num,              // № удостоверения
  "",                     // Рег. номер
